//! Jellyfin media-server plugin. Client + tool surface.
//!
//! Tool surface (one-tool-per-resource):
//!
//! - `jellyfin.{list, detail, create, update, delete}` — endpoint registry
//!   CRUD, generated by `endpoint_resource!` from the toolkit.
//! - `jellyfin.server_info` — server name / version / OS from `/System/Info`.
//! - `jellyfin.libraries` — configured libraries from `/Library/VirtualFolders`.
//! - `jellyfin.transcode_health` — **core diagnosis.** Per-session transcode
//!   state from `/Sessions`, flagging hardware-vs-software fallback.
//!
//! Endpoint resolution: tools accept the endpoint *name* and load
//! `(base_url, token)` from the toolkit-generated `tools::endpoint_db` at call
//! time, mirroring the dockge plugin. Per [[project-colocated-api-clients]] +
//! model B (any creds-holder may execute), the row syncs to every paired peer.
//!
//! ## Typed upstream client
//!
//! `progenitor` generates a typed `jellyfin::api::Client` at build time from
//! the vendored spec (pruned to the driven endpoints — see `build.rs`). The
//! generated types do not derive `JsonSchema`, so they never cross an
//! `#[orca_tool]` boundary; the tool surface deserializes upstream JSON into
//! the schema-deriving structs in `diag`. The generated module is retained as
//! the typed transport contract and is exercised by the hand-written `Client`
//! below through its shared base URL + auth header.
// Generated progenitor code triggers a raft of pedantic lints; the upstream
// session/transcode payloads are also modeled opaquely where untyped.
#![allow(clippy::disallowed_types)]

pub mod diag;
pub mod lifecycle;
pub mod tools;

use plugin_toolkit::http::{Client as HttpClient, HttpError, Response};
use plugin_toolkit::thiserror::Error;

use crate::diag::{RawSession, SessionTranscodeHealth};

/// Typed upstream client generated by progenitor from the pruned spec.
#[allow(
    clippy::all,
    dead_code,
    unused_imports,
    unused_variables,
    non_snake_case
)]
pub mod api {
    include!(concat!(env!("OUT_DIR"), "/jellyfin_codegen.rs"));
}

#[derive(Debug, Clone)]
pub struct Config {
    pub base_url: String,
    pub token: String,
}

impl Config {
    pub fn new(base_url: impl Into<String>, token: impl Into<String>) -> Self {
        Self {
            base_url: base_url.into(),
            token: token.into(),
        }
    }
}

#[derive(Debug, Error)]
pub enum JellyfinError {
    #[error(transparent)]
    Http(#[from] HttpError),
    #[error("decode {what}: {source}")]
    Decode {
        what: &'static str,
        #[source]
        source: plugin_toolkit::serde_json::Error,
    },
}

/// Server identity from `/System/Info`. Derives `JsonSchema` because the
/// `jellyfin.server_info` tool returns it directly across the tool boundary.
#[derive(
    Debug,
    Clone,
    plugin_toolkit::serde::Serialize,
    plugin_toolkit::serde::Deserialize,
    plugin_toolkit::schemars::JsonSchema,
)]
#[serde(crate = "plugin_toolkit::serde")]
#[schemars(crate = "plugin_toolkit::schemars")]
#[serde(rename_all = "PascalCase")]
pub struct ServerInfo {
    #[serde(default)]
    pub server_name: Option<String>,
    #[serde(default)]
    pub version: Option<String>,
    #[serde(default)]
    pub operating_system: Option<String>,
    #[serde(default)]
    pub id: Option<String>,
}

/// One configured library from `/Library/VirtualFolders`.
#[derive(
    Debug,
    Clone,
    plugin_toolkit::serde::Serialize,
    plugin_toolkit::serde::Deserialize,
)]
#[serde(crate = "plugin_toolkit::serde")]
#[serde(rename_all = "PascalCase")]
pub struct VirtualFolder {
    #[serde(default)]
    pub name: Option<String>,
    #[serde(default)]
    pub collection_type: Option<String>,
    #[serde(default)]
    pub locations: Option<Vec<String>>,
    #[serde(default)]
    pub item_id: Option<String>,
}

/// Hand-written transport. Carries the Jellyfin API token on every request as
/// `Authorization: MediaBrowser Token="<token>"` — the wire format the
/// Jellyfin web client and `/System/Info` accept.
#[derive(Clone)]
pub struct Client {
    cfg: Config,
    http: HttpClient,
}

impl Client {
    pub fn new(cfg: Config) -> Self {
        Self {
            cfg,
            http: HttpClient::new(),
        }
    }

    pub fn with_http(cfg: Config, http: HttpClient) -> Self {
        Self { cfg, http }
    }

    /// Server name / version / OS.
    pub async fn server_info(&self) -> Result<ServerInfo, JellyfinError> {
        let resp = self.authed_get("/System/Info").await?;
        resp.json::<ServerInfo>().map_err(JellyfinError::Http)
    }

    /// Configured libraries.
    pub async fn libraries(&self) -> Result<Vec<VirtualFolder>, JellyfinError> {
        let resp = self.authed_get("/Library/VirtualFolders").await?;
        resp.json::<Vec<VirtualFolder>>()
            .map_err(JellyfinError::Http)
    }

    /// Active sessions, classified for transcode health.
    pub async fn transcode_health(&self) -> Result<Vec<SessionTranscodeHealth>, JellyfinError> {
        let resp = self.authed_get("/Sessions").await?;
        let raw = resp
            .json::<Vec<RawSession>>()
            .map_err(JellyfinError::Http)?;
        Ok(raw
            .into_iter()
            .map(SessionTranscodeHealth::from_raw)
            .collect())
    }

    /// Liveness probe. A bare authed GET of `/System/Info` that returns the
    /// HTTP status so a caller can distinguish "served fast" from "timed out /
    /// 5xx under memory thrash" — the real-I/O pressure signal observable from
    /// outside the guest. Errors (timeout, connection refused) propagate.
    pub async fn liveness(&self) -> Result<u16, JellyfinError> {
        Ok(self.authed_get("/System/Info").await?.status)
    }

    /// Restart the Jellyfin application via `POST /System/Restart`
    /// (`RestartApplication`). This reaps the server's transcode child
    /// processes (the ffmpeg workers that drive memory growth) and releases
    /// the accumulated anonymous heap — the service-layer equivalent of the
    /// guest restart, owned by this plugin rather than the host runtime.
    pub async fn restart(&self) -> Result<(), JellyfinError> {
        self.http
            .post(self.url("/System/Restart"))
            .header(
                "authorization",
                format!("MediaBrowser Token=\"{}\"", self.cfg.token),
            )
            .send()
            .await?;
        Ok(())
    }

    async fn authed_get(&self, path: &str) -> std::result::Result<Response, HttpError> {
        self.http
            .get(self.url(path))
            .header(
                "authorization",
                format!("MediaBrowser Token=\"{}\"", self.cfg.token),
            )
            .header("accept", "application/json")
            .send()
            .await
    }

    fn url(&self, path: &str) -> String {
        format!("{}{}", self.cfg.base_url.trim_end_matches('/'), path)
    }
}

#[cfg(test)]
mod tests {
    use plugin_toolkit::serde_json;
    use wiremock::matchers::{header, method, path};
    use wiremock::{Mock, MockServer, ResponseTemplate};

    use super::*;

    #[tokio::test]
    async fn server_info_parses() {
        let server = MockServer::start().await;
        Mock::given(method("GET"))
            .and(path("/System/Info"))
            .and(header("authorization", "MediaBrowser Token=\"tok\""))
            .respond_with(ResponseTemplate::new(200).set_body_json(serde_json::json!({
                "ServerName": "media",
                "Version": "10.9.0",
                "OperatingSystem": "Linux"
            })))
            .mount(&server)
            .await;
        let info = Client::new(Config::new(server.uri(), "tok"))
            .server_info()
            .await
            .unwrap();
        assert_eq!(info.version.as_deref(), Some("10.9.0"));
    }

    #[tokio::test]
    async fn transcode_health_flags_software_fallback() {
        let server = MockServer::start().await;
        Mock::given(method("GET"))
            .and(path("/Sessions"))
            .respond_with(ResponseTemplate::new(200).set_body_json(serde_json::json!([
                {
                    "Id": "a",
                    "UserName": "scott",
                    "NowPlayingItem": { "Name": "Film" },
                    "TranscodingInfo": { "HardwareAccelerationType": "none" }
                },
                {
                    "Id": "b",
                    "UserName": "scott",
                    "NowPlayingItem": { "Name": "Show" },
                    "TranscodingInfo": { "HardwareAccelerationType": "qsv" }
                },
                { "Id": "c", "UserName": "scott" }
            ])))
            .mount(&server)
            .await;
        let sessions = Client::new(Config::new(server.uri(), "tok"))
            .transcode_health()
            .await
            .unwrap();
        assert_eq!(sessions.len(), 3);
        assert!(sessions[0].software_fallback);
        assert!(!sessions[1].software_fallback);
        assert!(!sessions[2].is_transcoding);
    }

    #[tokio::test]
    async fn liveness_reports_status_and_errors_on_5xx() {
        let server = MockServer::start().await;
        Mock::given(method("GET"))
            .and(path("/System/Info"))
            .respond_with(ResponseTemplate::new(200).set_body_json(serde_json::json!({})))
            .mount(&server)
            .await;
        let client = Client::new(Config::new(server.uri(), "tok"));
        assert_eq!(client.liveness().await.unwrap(), 200);

        // A server thrashing under memory pressure answers 5xx — liveness
        // surfaces that as an error, which the memory guard reads as pressure.
        let down = MockServer::start().await;
        Mock::given(method("GET"))
            .and(path("/System/Info"))
            .respond_with(ResponseTemplate::new(503))
            .mount(&down)
            .await;
        assert!(
            Client::new(Config::new(down.uri(), "tok"))
                .liveness()
                .await
                .is_err()
        );
    }

    #[tokio::test]
    async fn restart_posts_system_restart() {
        let server = MockServer::start().await;
        Mock::given(method("POST"))
            .and(path("/System/Restart"))
            .and(header("authorization", "MediaBrowser Token=\"tok\""))
            .respond_with(ResponseTemplate::new(204))
            .expect(1)
            .mount(&server)
            .await;
        Client::new(Config::new(server.uri(), "tok"))
            .restart()
            .await
            .unwrap();
        // wiremock verifies the single expected POST on drop.
    }
}
